let allData = {{workflowparams:allData}}
const saveAs = {{workflowparams:saveAs}}
const updatedPRT = []

const formatNumber = (value) => {
  if (value === null || value === undefined || value === "") return 0;
  return parseFloat(value).toFixed(3);
};

const lines = allData.table_prt || [];
for (const prtLineItem of lines) {
  // For a completed return, drop zero-return-qty lines (the client already
  // confirmed their removal). Drafts keep every line.
  if (saveAs !== "Draft" && !(parseFloat(prtLineItem.return_quantity) > 0)) continue;

  prtLineItem.return_quantity = formatNumber(prtLineItem.return_quantity);
  prtLineItem.received_qty = formatNumber(prtLineItem.received_qty);
  prtLineItem.unit_price = formatNumber(prtLineItem.unit_price);

  prtLineItem.supplier_id = allData.supplier_id || null;
  prtLineItem.plant_id = allData.plant || null;
  prtLineItem.billing_state_id = allData.billing_address_state || null;
  prtLineItem.billing_country_id = allData.billing_address_country || null;
  prtLineItem.shipping_state_id = allData.shipping_address_state || null;
  prtLineItem.shipping_country_id = allData.shipping_address_country || null;
  prtLineItem.organization_id = allData.organization_id;

  updatedPRT.push(prtLineItem);
}

updatedPRT.forEach((line, index) => { line.line_index = index + 1; });
allData.table_prt = updatedPRT;

allData.po_id = [...new Set(updatedPRT.map((r) => r.po_id).filter((x) => x))];
allData.gr_id = [...new Set(updatedPRT.map((r) => r.gr_id).filter((x) => x))];
allData.po_no_display = [...new Set(updatedPRT.map((r) => r.po_number).filter((x) => x))].join(", ");
allData.gr_no_display = [...new Set(updatedPRT.map((r) => r.gr_number).filter((x) => x))].join(", ");

if (saveAs === "Draft") {
  if (allData.purchase_return_no_type !== -9999 && (!allData.purchase_return_no || allData.purchase_return_no === null || allData.purchase_return_no === "")) {
    allData.purchase_return_no = "draft";
  }
} else {
  if (allData.purchase_return_no_type !== -9999 && (!allData.purchase_return_no || allData.purchase_return_no === null || allData.purchase_return_no === "" || allData.previous_status === "Draft")) {
    allData.purchase_return_no = "issued";
  }
}

allData.purchase_return_status = saveAs === "Draft" ? "Draft" : saveAs === "Created" ? "Created" : "Completed";

if (allData.acc_integration_type && allData.acc_integration_type !== "No Accounting Integration") {
  allData.posted_status = "Unposted";
}

return {
  allData: allData,
  purchase_return_status: allData.purchase_return_status,
}

return {
  required_fields: JSON.stringify([
    { name: "plant", label: "Plant" },
    { name: "purchase_return_no", label: "Purchase Return No" },
    {
      name: "table_prt",
      label: "Item Information",
      isArray: true,
      arrayType: "object",
      arrayFields: [],
    },
  ]),
  data: JSON.stringify({
    plant: {{node:code_node_ISWz5KGY.data.allData.plant}},
    purchase_return_no: {{node:code_node_ISWz5KGY.data.allData.purchase_return_no}},
    table_prt: {{node:code_node_ISWz5KGY.data.allData.table_prt}}
  })
}

const allData = {{node:code_node_ISWz5KGY.data.allData}}
const subformData = allData.table_prt || []

let quantityFailed = 0
let quantityMessage

const hasQuantity = subformData.some((line) => {
  if (!line.temp_qty_data) return false;
  try {
    const parsed = JSON.parse(line.temp_qty_data);
    return Array.isArray(parsed) && parsed.some(
      (entry) => entry.return_quantity && parseFloat(entry.return_quantity) > 0
    );
  } catch (e) {
    return false;
  }
});

if (!hasQuantity) {
  quantityFailed = 1
  quantityMessage = 'No quantity selected to return'
}

return { quantityFailed: quantityFailed, quantityMessage: quantityMessage };

const page_status = {{workflowparams:pageStatus}};
const allData = {{node:code_node_ISWz5KGY.data.allData}}
const subformData = allData.table_prt;

const plant_id = allData.plant;
const organization_id = allData.organization_id;
const purchase_return_no = allData.purchase_return_no;
const doc_date = allData.purchase_return_date;

const item = {{node:loop_C4YuLV2v}};
const material_id = item.material_id;
const material_uom = item.return_uom_id;
const total_quantity = item.return_quantity;
const location_id = item.location_id;
const batch_id = item.batch_id || null;
const inventory_category = "Unrestricted";

let balancesToProcess = [];
const tempData = item.temp_qty_data;
if (tempData) {
  try {
    const parsed = JSON.parse(tempData);
    if (Array.isArray(parsed)) {
      balancesToProcess = parsed.filter(
        (entry) => entry.return_quantity && parseFloat(entry.return_quantity) > 0
      );
    }
  } catch (e) {
    balancesToProcess = [];
  }
}

return {
  plant_id: plant_id,
  organization_id: organization_id,
  purchase_return_no: purchase_return_no,
  page_status: page_status,
  material_id: material_id,
  material_uom: material_uom,
  total_quantity: total_quantity,
  location_id: location_id,
  batch_id: batch_id,
  inventory_category: inventory_category,
  doc_date: doc_date,
  balancesToProcess: balancesToProcess
};

const balance = {{node:loop_9XodkC0Z}};
const batch_id = balance.batch_id || null;
const location_id = balance.location_id;
const quantity = balance.return_quantity;
const inventory_category = balance.inventory_category;
const manufacturing_date = balance.manufacturing_date || null;
const expired_date = balance.expired_date || null;
const handling_unit_id = balance.handling_unit_id || null;

return {
  batch_id: batch_id,
  location_id: location_id,
  quantity: quantity,
  inventory_category: inventory_category,
  manufacturing_date: manufacturing_date,
  expired_date: expired_date,
  handling_unit_id: handling_unit_id
};

const newLines = {{node:code_node_ISWz5KGY.data.allData.table_prt}} || [];

let origRaw = {{node:search_origPRT.data.data}} || [];
if (!Array.isArray(origRaw)) origRaw = [origRaw];
const origPRT = origRaw[0] || null;
const origLines = origPRT && Array.isArray(origPRT.table_prt) ? origPRT.table_prt : [];

// Union of the new and the pre-edit lines. A line that was deleted — or zeroed, and
// so dropped by fillback — still holds a created_return_qty on its GR/PO, and those
// rows have to be fetched or the reservation is stranded forever.
const all = newLines.concat(origLines);
const uniq = (key) => [...new Set(all.map((l) => l[key]).filter((x) => x))];

// Sentinel keeps the equalAny filter well-formed when nothing is linked; it matches nothing.
const orNone = (arr) => (arr.length > 0 ? arr : ["__none__"]);

return {
  grIds: orNone(uniq("gr_id")),
  poLineIds: orNone(uniq("po_line_id")),
  // Item ids for the batched Item fetch that rides cond_all_PRTsync
  // (replaces a per-line get-node inside loop_BBZNjfzE).
  itemIds: orNone(uniq("material_id")),
};

const roundQty = (v) => parseFloat(parseFloat(v || 0).toFixed(3));

const allData = {{node:code_node_ISWz5KGY.data.allData}} || {};
const pageStatus = {{workflowparams:pageStatus}};

let grHeads = {{node:search_grHeads.data.data}} || [];
if (!Array.isArray(grHeads)) grHeads = [grHeads];
let origRaw = {{node:search_origPRT.data.data}} || [];
if (!Array.isArray(origRaw)) origRaw = [origRaw];
const origPRT = origRaw[0] || null;

// Only a previously-Created document already holds a reservation on these GR lines.
const hadReservation =
  pageStatus === "Edit" && origPRT && origPRT.purchase_return_status === "Created";
const origLines = hadReservation && Array.isArray(origPRT.table_prt) ? origPRT.table_prt : [];

const aggregate = (rows) => {
  const m = {};
  for (const r of rows || []) {
    const k = r.gr_line_id;
    if (!k) continue;
    m[k] = roundQty((m[k] || 0) + parseFloat(r.return_quantity || 0));
  }
  return m;
};

const requested = aggregate(allData.table_prt);
const ownOld = aggregate(origLines);

const grLineById = {};
for (const gr of grHeads) {
  for (const it of gr.table_gr || []) grLineById[it.id] = it;
}

// received_qty is taken from the PRT row, not the GR line. For a serialized item the row
// is converted to base UOM, and so are the quantities booked back onto the GR line, while
// the GR line's own received_qty stays in the receiving UOM. Reading the row keeps both
// sides of the subtraction in the same unit.
const receivedById = {};
for (const line of allData.table_prt || []) {
  if (line.gr_line_id) receivedById[line.gr_line_id] = roundQty(line.received_qty);
}

const offenders = [];
for (const grLineId of Object.keys(requested)) {
  const grLine = grLineById[grLineId];
  if (!grLine) continue; // line no longer on the goods receiving; nothing to check against

  const received = receivedById[grLineId] || 0;
  const returned = roundQty(grLine.return_quantity);
  const reserved = roundQty(grLine.created_return_qty);

  // This document's own reservation is about to be replaced, so it is still available to
  // it. What any other document returned or reserved is not. The client-side dialog cap
  // uses a returned_quantity snapshotted when the row was added, so it goes stale as soon
  // as a sibling purchase return touches the same line — this is the authoritative check.
  const available = roundQty(received - returned - reserved + (ownOld[grLineId] || 0));
  const want = requested[grLineId];

  if (want > available + 0.0005) {
    const label = grLine.item_name || grLine.item_desc || grLineId;
    offenders.push(
      label + ": returning " + want + ", only " + Math.max(0, available) + " still returnable",
    );
  }
}

let returnableFailed = 0;
let returnableMessage = "";
if (offenders.length > 0) {
  returnableFailed = 1;
  returnableMessage =
    "Return quantity exceeds what is still returnable on the goods receiving:\n" +
    offenders.join("\n");
}

return { returnableFailed: returnableFailed, returnableMessage: returnableMessage };

const page_status = {{workflowparams:pageStatus}};
let allData;
if (page_status === "Add") {
  const rawData = {{node:add_node_1p1Kdkhz.data}}
  allData = Array.isArray(rawData) ? rawData[0] : rawData;
} else if (page_status === "Edit") {
  allData = {{node:get_node_7CFMbGI0.data.data}}
} else {
  allData = {{node:code_node_ISWz5KGY.data.allData}}
}

const plant_id = allData.plant;
const organization_id = allData.organization_id;
const purchase_return_no = allData.purchase_return_no;
const doc_date = allData.purchase_return_date;

const item = {{node:loop_BBZNjfzE}};
const material_id = item.material_id;
const material_uom = item.return_uom_id;
const total_quantity = item.return_quantity;
const location_id = item.location_id;
const batch_id = item.batch_id || null;
const parentNo = item.gr_number || item.po_no_display || allData.po_no_display || null;
const inventory_category = "Unrestricted";

let balancesToProcess = [];
const tempData = item.temp_qty_data;
if (tempData) {
  try {
    const parsed = JSON.parse(tempData);
    if (Array.isArray(parsed)) {
      balancesToProcess = parsed.filter(
        (entry) => entry.return_quantity && parseFloat(entry.return_quantity) > 0
      );
    }
  } catch (e) {
    balancesToProcess = [];
  }
}

balancesToProcess = balancesToProcess.map((entry) => ({ ...entry, po_no: parentNo }));

// itemData for SUBTRACT_INVENTORY, from the single batched Item fetch that
// rides cond_all_PRTsync (previously one get-node per loop iteration).
const itemsRaw = {{node:search_PRTitems.data.data}} || [];
const itemsArr = Array.isArray(itemsRaw) ? itemsRaw : [itemsRaw];
const itemData = itemsArr.find(i => i && String(i.id) === String(material_id)) || null;

return {
  itemData: itemData,
  plant_id: plant_id,
  organization_id: organization_id,
  purchase_return_no: purchase_return_no,
  page_status: page_status,
  material_id: material_id,
  material_uom: material_uom,
  total_quantity: total_quantity,
  location_id: location_id,
  batch_id: batch_id,
  inventory_category: inventory_category,
  doc_date: doc_date,
  balancesToProcess: balancesToProcess
};

const balance = {{node:loop_NWeT5dSb}};
const batch_id = balance.batch_id || null;
const location_id = balance.location_id;
const quantity = balance.return_quantity;
let inventory_category = balance.inventory_category || "Unrestricted";
const manufacturing_date = balance.manufacturing_date || null;
const expired_date = balance.expired_date || null;
const po_no = balance.po_no || null;

return {
  batch_id: batch_id,
  location_id: location_id,
  quantity: quantity,
  inventory_category: inventory_category,
  manufacturing_date: manufacturing_date,
  expired_date: expired_date,
  po_no: po_no
};

const allData = {{node:code_node_ISWz5KGY.data.allData}};
const subformData = allData.table_prt || [];
const plantId = allData.plant;
const organizationId = allData.organization_id;

const huUpdatesMap = new Map();
for (const line of subformData) {
  if (!line.temp_qty_data) continue;
  let entries;
  try {
    entries = JSON.parse(line.temp_qty_data);
  } catch (e) {
    continue;
  }
  if (!Array.isArray(entries)) continue;

  for (const entry of entries) {
    const huId = entry.handling_unit_id;
    if (!huId) continue;
    const qty = parseFloat(entry.return_quantity || 0);
    if (qty <= 0) continue;

    if (!huUpdatesMap.has(huId)) {
      huUpdatesMap.set(huId, {
        handling_unit_id: huId,
        plant_id: plantId,
        organization_id: organizationId,
        location_id: entry.location_id || null,
        storage_location_id: entry.storage_location_id || null,
        items: [],
      });
    }
    const update = huUpdatesMap.get(huId);

    const key = `${entry.material_id}__${entry.balance_id || ""}__${entry.batch_id || ""}`;
    const existing = update.items.find(
      (i) => `${i.material_id}__${i.balance_id || ""}__${i.batch_id || ""}` === key
    );
    if (existing) {
      existing.quantity += qty;
    } else {
      update.items.push({
        material_id: entry.material_id,
        balance_id: entry.balance_id || "",
        batch_id: entry.batch_id || null,
        quantity: qty,
      });
    }
  }
}

return {
  huUpdates: Array.from(huUpdatesMap.values()),
  huUpdatesLength: huUpdatesMap.size,
};

const u = {{node:loop_ONoGvpqr}};
return {
  handling_unit_id: u.handling_unit_id,
  plant_id: u.plant_id,
  organization_id: u.organization_id,
  location_id: u.location_id,
  storage_location_id: u.storage_location_id,
  table_hu_items: u.items,
};

const roundQty = (v) => parseFloat(parseFloat(v || 0).toFixed(3));
const asStr = (v) => Math.max(0, roundQty(v)).toFixed(3);

const allData = {{node:code_node_ISWz5KGY.data.allData}} || {};
const saveAs = {{workflowparams:saveAs}};
const pageStatus = {{workflowparams:pageStatus}};

let poLines = {{node:search_poLines.data.data}} || [];
if (!Array.isArray(poLines)) poLines = [poLines];
let grHeads = {{node:search_grHeads.data.data}} || [];
if (!Array.isArray(grHeads)) grHeads = [grHeads];
let origRaw = {{node:search_origPRT.data.data}} || [];
if (!Array.isArray(origRaw)) origRaw = [origRaw];
const origPRT = origRaw[0] || null;

// Only a PRT that was already "Created" holds a reservation. Editing a Draft (or
// adding) has nothing to diff against, so oldAgg stays empty and the Completed
// path degrades to a plain "return_quantity += new".
const hadReservation =
  pageStatus === "Edit" && origPRT && origPRT.purchase_return_status === "Created";
const origLines = hadReservation && Array.isArray(origPRT.table_prt) ? origPRT.table_prt : [];

const aggregate = (rows, key) => {
  const m = {};
  for (const r of rows || []) {
    const k = r[key];
    if (!k) continue;
    m[k] = roundQty((m[k] || 0) + parseFloat(r.return_quantity || 0));
  }
  return m;
};

const newByPoLine = aggregate(allData.table_prt, "po_line_id");
const oldByPoLine = aggregate(origLines, "po_line_id");
const newByGrLine = aggregate(allData.table_prt, "gr_line_id");
const oldByGrLine = aggregate(origLines, "gr_line_id");

const isCreated = saveAs === "Created";

// Created  : created_return_qty += (new - old)          return_quantity untouched
// Completed: created_return_qty -= old  AND  return_quantity += new  (one write)
const apply = (curCreated, curReturn, nq, oq) =>
  isCreated
    ? { created: Math.max(0, roundQty(curCreated + nq - oq)), returned: curReturn }
    : {
        created: Math.max(0, roundQty(curCreated - oq)),
        returned: Math.max(0, roundQty(curReturn + nq)),
      };

const poLineUpdates = [];
for (const line of poLines) {
  const curCreated = roundQty(line.created_return_qty);
  const curReturn = roundQty(line.return_quantity);
  const next = apply(curCreated, curReturn, newByPoLine[line.id] || 0, oldByPoLine[line.id] || 0);
  if (next.created === curCreated && next.returned === curReturn) continue;
  poLineUpdates.push({
    id: line.id,
    created_return_qty: asStr(next.created),
    return_quantity: asStr(next.returned),
  });
}

const grUpdates = [];
for (const gr of grHeads) {
  const items = (gr.table_gr || []).map((it) => ({ ...it }));
  let changed = false;
  for (const it of items) {
    const curCreated = roundQty(it.created_return_qty);
    const curReturn = roundQty(it.return_quantity);
    const next = apply(curCreated, curReturn, newByGrLine[it.id] || 0, oldByGrLine[it.id] || 0);
    if (next.created !== curCreated || next.returned !== curReturn) changed = true;
    it.created_return_qty = asStr(next.created);
    it.return_quantity = asStr(next.returned);
  }

  // Split children are per-bin detail; only parent/regular rows are returnable, and
  // PRT lines only ever target those. Counting children would make "Fully Returned"
  // unreachable for any split goods receiving.
  const returnable = items.filter((it) => it.parent_or_child !== "Child");

  let fully = 0;
  let partially = 0;
  let reserved = 0;
  for (const it of returnable) {
    const rq = parseFloat(it.return_quantity || 0);
    const cq = parseFloat(it.created_return_qty || 0);
    if (rq > 0) {
      partially++;
      if (rq >= parseFloat(it.received_qty || 0)) fully++;
    }
    if (cq > 0) reserved++;
  }
  let status = "";
  if (returnable.length > 0 && fully === returnable.length) status = "Fully Returned";
  else if (partially > 0) status = "Partially Returned";
  else if (reserved > 0) status = "Created";

  if (!changed && status === (gr.return_status || "")) continue;
  grUpdates.push({ id: gr.id, table_gr: items, return_status: status });
}

return {
  poLineUpdates: poLineUpdates,
  grUpdates: grUpdates,
  hasPoUpdates: poLineUpdates.length > 0 ? 1 : 0,
  hasGrUpdates: grUpdates.length > 0 ? 1 : 0,
};

const tablePRT = {{node:code_node_ISWz5KGY.data.allData.table_prt}}

const uniqueItemIds = [
  ...new Set(
    tablePRT
      .filter((item) => item.material_id)
      .map((item) => item.material_id),
  ),
];

const date = new Date().toISOString();
const updates = [];
for (const itemId of uniqueItemIds) {
  updates.push({ id: itemId, last_transaction_date: date });
}

return { updates: updates };
